function getPlan(day){ return activeMealPlan().filter(r=>r.Day===day); }
function mealKey(m){ return `${m['Meal Code']}|${m.Slot}`; }
function mealMacros(m){ return {cal:num(m.Calories), protein:num(m['Protein g']), carbs:num(m['Carbs g']), fat:num(m['Fat g']), fibre:num(m['Fibre g'])}; }
function mealNutrition(m){ const values=mealMacros(m); MICRO_FIELDS.forEach(([key])=>values[key]=0); MICRO_FIELDS.forEach(([key,,field])=>values[key]=num(m[field])); return values; }
function addMacro(a,b){ a.cal+=num(b.cal); a.protein+=num(b.protein); a.carbs+=num(b.carbs); a.fat+=num(b.fat); a.fibre+=num(b.fibre); return a; }
function emptyMacro(){ return {cal:0,protein:0,carbs:0,fat:0,fibre:0}; }
function emptyNutrition(){ const t=emptyMacro(); MICRO_FIELDS.forEach(([key])=>t[key]=0); return t; }
function addNutrition(a,b){ addMacro(a,b); MICRO_FIELDS.forEach(([key])=>a[key]+=num(b[key])); return a; }
function customMealNutrition(m){ const t={cal:m.calories,protein:m.protein,carbs:m.carbs,fat:m.fat,fibre:m.fibre}; MICRO_FIELDS.forEach(([key])=>t[key]=num(m[key])); return t; }
function metricsFor(date){ const log=getLog(date); const day=planDayForDate(date); const totals=emptyNutrition(); getPlan(day).forEach(m=>{ if(log.meals[mealKey(m)]) addNutrition(totals, mealNutrition(m)); }); (log.customMeals||[]).forEach(m=>addNutrition(totals, customMealNutrition(m))); totals.cal += num(log.beers)*170; totals.carbs += num(log.beers)*12; return totals; }
function plannedTotalsFor(day){ const t=emptyNutrition(); getPlan(day).forEach(m=>addNutrition(t, mealNutrition(m))); return t; }
