function addRecipeToWeek(id, day=planDayForDate(selectedDate)){ const r=findRecipe(id); if(!r) return toast('Recipe not found'); const plans=plannedRecipes(); const list=plans[day] || []; const recipeId=recipeLookupId({...r, custom:id.startsWith('custom:')}); if(!list.some(x=>x.id===recipeId)) list.push({id:recipeId,title:r.title||'Recipe'}); plans[day]=list; savePlannedRecipes(plans); toast(`Planned for ${day}`); render(); }
