function recommendationFor(date=selectedDate){ const log=getLog(date); const day=planDayForDate(date); const total=metricsFor(date); const planned=plannedTotalsFor(day); const proteinGap=Math.max(0, Math.round((planned.protein || 130)-total.protein)); const fibreGap=Math.max(0, Math.round((planned.fibre || 30)-total.fibre)); const t=template(); let title='Next step'; let action='Update meals. Add quick option if needed.'; let detail=`${t.name}: ${t.focus}`; let preset='protein-shake'; if(log.training && log.training!=='none'){ title='Training day'; action=proteinGap>25?'Protein low. Add quick option.':'Protein ok. Add only if needed.'; preset='banana-milk'; }
  else if(log.eatout && log.eatout!=='none'){ title='Flexible day'; action=proteinGap>25?'Protein low. Add quick option.':'Estimate it. Move on.'; preset='wrap'; }
  else if(log.morning==='skipped' || total.protein<35){ title='Protein low'; action='Add quick option.'; preset='banana-milk'; }
  else if(fibreGap>12){ title='Fibre low'; action='Add quick option or recipe.'; preset='yoghurt-muesli'; }
  else if(proteinGap>35){ title='Protein gap'; action='Add quick option or recipe.'; preset='protein-shake'; }
  else { title='On track'; action='Keep logging.'; preset='sushi'; }
  if(t.id==='low-appetite'){ action='Add quick option or stop here.'; preset='banana-milk'; }
  if(t.id==='social'){ detail='Social template.'; if(!log.beers && log.eatout==='none') action='Log beers if needed.'; }
  return {title, action, detail, proteinGap, fibreGap, preset, template:t}; }
