function recipeNutrition(r){ if(r.nutrition){ return {cal:num(r.nutrition.Calories),protein:num(r.nutrition['Protein g']),carbs:num(r.nutrition['Carbs g']),fat:num(r.nutrition['Fat g']),fibre:num(r.nutrition['Fibre g'])}; } return {cal:num(r.calories),protein:num(r.protein),carbs:num(r.carbs),fat:num(r.fat),fibre:num(r.fibre)}; }
function recipeLookupId(r){ return r.custom ? `custom:${r.id}` : (r.code || r.id); }
function findRecipe(id){ if(!id) return null; if(id.startsWith('custom:')) return customRecipes().find(x=>`custom:${x.id}`===id); return allRecipes().find(x=>x.code===id || x.id===id); }
function parseIngredientLine(line){ const text=String(line||'').trim(); if(!text) return null; const chunks=text.includes('|') ? text.split('|').map(x=>x.trim()) : text.split(/\s+-\s+/).map(x=>x.trim()); return {ingredient:chunks[0]||'',amount:chunks[1]||'',category:chunks[2]||'Recipe add-ons',notes:chunks.slice(3).join(' | ')}; }
function looksLikeInstructionIngredient(ingredient){ return /^(mix|cut|pan-fry|grill|serve|cook|reheat|add|warm|top|stir|spread)\b/i.test(String(ingredient||'')); }
function looksLikeMethodIngredient(ingredient,amount,rawCategory,notes){ return (!amount && !notes && String(rawCategory).match(/^\d+$/)) || (!amount && looksLikeInstructionIngredient(ingredient)); }
function normalizeRecipeIngredient(x){ if(typeof x==='string') return parseIngredientLine(x); const ingredient=x.Ingredient||x.ingredient||x.name||''; const amount=x['Metric amount']||x.amount||x.quantity||''; const rawCategory=x.category||x.Section||'Recipe add-ons'; const notes=x.Notes||x.notes||x['Used in']||''; if(!ingredient || looksLikeMethodIngredient(ingredient,amount,rawCategory,notes)) return null; const category=String(rawCategory).match(/^\d+$/)?'Recipe add-ons':rawCategory; return {ingredient,amount,category,notes}; }
function recipeIngredientEntries(r){ if(Array.isArray(r.ingredientList)) return r.ingredientList.map(normalizeRecipeIngredient).filter(Boolean); if(Array.isArray(r.ingredients)) return r.ingredients.map(normalizeRecipeIngredient).filter(Boolean); if(typeof r.ingredients==='string') return r.ingredients.split(/\n|,/).map(parseIngredientLine).filter(Boolean); if(Array.isArray(r.shopping)) return r.shopping.map(parseIngredientLine).filter(Boolean).map(normalizeRangeIngredient).filter(x=>x.ingredient); return []; }
