function renderBeerModal(log){ return `<div class="modal-backdrop" data-modal-backdrop><div class="card modal-card" role="dialog" aria-modal="true" aria-labelledby="beerModalTitle"><div class="section-title"><div><h2 id="beerModalTitle">Beers</h2><p>${esc(selectedDate)}</p></div><button class="icon-btn" data-action="close-beer-modal" aria-label="Close">&times;</button></div><label>Count</label><input id="beerModalCount" type="number" min="0" step="1" inputmode="numeric" value="${esc(beerCountValue(log.beers))}" aria-label="Beer count"><div class="badges modal-actions"><button class="btn primary" data-action="save-beer-modal">Save</button><button class="btn" data-action="close-beer-modal">Cancel</button></div></div></div>`; }
function renderCopyFallback(){ return `<div class="modal-backdrop"><div class="card modal-card copy-modal" role="dialog" aria-modal="true" aria-labelledby="copyFallbackTitle"><div class="section-title"><div><h2 id="copyFallbackTitle">${esc(copyFallback.title||'Copy text')}</h2><p>Automatic clipboard copy was blocked. Select and copy this text manually.</p></div><button class="icon-btn" data-action="close-copy-fallback" aria-label="Close">&times;</button></div><textarea id="copyFallbackText" readonly>${esc(copyFallback.text||'')}</textarea><div class="badges modal-actions"><button class="btn primary" data-action="select-copy-text">Select text</button><button class="btn" data-action="retry-copy">Try copy again</button><button class="btn" data-action="close-copy-fallback">Close</button></div></div></div>`; }
function updateBeerCount(value, rerender=false){ const log=getLog(); log.beers=beerCountValue(value); setLog(selectedDate,log); document.querySelectorAll('[data-log-field="beers"]').forEach(el=>{ el.value=String(log.beers); }); if(rerender) render(); return log.beers; }
function quickPresetTitle(id){ return allQuickMealPresets().find(x=>x.id===id)?.title || 'quick option'; }
function renderTemplatePill(){ return `<label class="badge template-pill"><span>Week</span><select data-template-select aria-label="Week type">${WEEK_TEMPLATES.map(x=>`<option value="${esc(x.id)}" ${x.id===activeTemplate?'selected':''}>${esc(x.name)}</option>`).join('')}</select></label>`; }
function renderTodayDecision(total, planned, log, score){ const rec=recommendationFor(selectedDate); const day=planDayForDate(selectedDate); const plannedList=plannedRecipesFor(day); const quickTitle=quickPresetTitle(rec.preset); return `<section class="card today-command"><div class="section-title"><div><h2>${esc(rec.title)}</h2><p>${esc(rec.action)}</p></div><span class="badge accent">${score}%</span></div><div class="badges today-stats"><span class="badge">${n(total.protein)}g protein</span><span class="badge">${n(total.fibre)}g fibre</span><span class="badge">${n(rec.proteinGap)}g gap</span>${renderBeerCountPill(log)}${renderTemplatePill()}</div><div class="badges" style="margin-top:10px"><button class="btn smallbtn primary" data-quick-preset="${esc(rec.preset)}">Add ${esc(quickTitle)}</button><button class="btn smallbtn" data-action="add-beer">+ Beer</button><button class="btn smallbtn" data-action="go-recipes">Recipes</button><button class="btn smallbtn" data-action="go-shop">Shop</button></div>${plannedList.length?`<hr><div class="list">${plannedList.map(x=>`<div class="row compact-row"><div class="row-left"><div class="row-title">${esc(x.title)}</div><div class="muted small">Planned</div></div><button class="btn smallbtn" data-add-recipe-to-day="${esc(x.id)}">Log</button></div>`).join('')}</div>`:''}</section>`; }
function renderNutritionPanel(logged, planned){ return `<div class="grid two mobile-two">${renderMacroTiles(logged, planned)}</div><hr><div class="grid three mobile-two">${MICRO_FIELDS.map(([key,label,,unit,target])=>renderMicroTile(label, logged[key], planned[key], target, unit)).join('')}</div>`; }
function renderMacroTiles(logged, planned){ return [['cal','Calories','kcal'],['protein','Protein','g'],['carbs','Carbs','g'],['fat','Fat','g'],['fibre','Fibre','g']].map(([key,label,unit])=>renderNutrientTile(label, logged[key], planned[key], unit)).join(''); }
function renderNutrientTile(label, logged, planned, unit){ const pct=planned?Math.min(100,Math.round(num(logged)/num(planned)*100)):0; const suffix=unit==='kcal'?' kcal':' '+unit; return `<div class="metric"><div class="num">${n(logged)}${suffix}</div><div class="lbl">${esc(label)} logged / ${n(planned)}${suffix} planned</div><div class="progress-track" style="margin-top:8px"><span style="width:${Math.max(2,pct)}%"></span></div></div>`; }
function renderMicroTile(label, logged, planned, target, unit){ const pct=Math.min(100,Math.round(num(logged)/target*100)); return `<div class="metric"><div class="num">${n(logged, unit==='g'?1:0)}${unit}</div><div class="lbl">${esc(label)} · planned ${n(planned, unit==='g'?1:0)}${unit}</div><div class="progress-track" style="margin-top:8px"><span style="width:${Math.max(2,pct)}%"></span></div></div>`; }
function renderMealCard(m){ const log=getLog(); const key=mealKey(m); const on=!!log.meals[key]; const macros=mealMacros(m); return `<div class="card meal-card compact-meal" style="margin:0"><input class="check" type="checkbox" ${on?'checked':''} data-meal-check="${esc(key)}" aria-label="Eaten"><div><div class="slot">${esc(m.Slot)}</div><div class="meal-title">${esc(m['Meal / slot'])}</div><div class="meal-portion">${esc(m['Portion / ingredients'])}</div><div class="meal-meta"><span class="badge accent">${n(macros.cal)} kcal</span><span class="badge">${n(macros.protein)}g protein</span><span class="badge">${n(macros.fibre)}g fibre</span></div></div></div>`; }
function renderCustomMealsBlock(log){ const customs=log.customMeals||[]; return `<details class="card flat extras-details" ${customs.length?'open':''}><summary class="recipe-summary"><div><div class="recipe-title">Extras</div><div class="muted small">${customs.length?`${customs.length} added`:'Optional'}</div></div><button class="btn smallbtn" data-action="show-quick-add">Quick add</button></summary><hr><div id="quickAdd" class="${customs.length?'':'hide'}"></div>${customs.length?`<div class="list">${customs.map((m,i)=>`<div class="row compact-row"><div class="row-left"><div class="row-title">${esc(m.title)}</div><div class="muted small">${n(m.calories)} kcal · ${n(m.protein)}g protein · ${n(m.fibre)}g fibre</div></div><button class="btn smallbtn danger" data-remove-custom-meal="${i}">Remove</button></div>`).join('')}</div>`:'<div class="muted small">Add only if today needs it.</div>'}</details>`; }
function renderDailyLogForm(log){ return `<details class="card flat daily-log-details"><summary class="recipe-summary"><div><div class="recipe-title">Optional details</div><div class="muted small">Context only.</div></div><span class="chev">&dtrif;</span></summary><hr><div class="form-grid">
    <div><label>Breakfast</label><select data-log-field="morning">${opts(['unset','skipped','micro','small','medium'],log.morning,'morning')}</select></div>
    <div><label>Training</label><select data-log-field="training">${opts(['none','light','hard'],log.training,'training')}</select></div>
    <div><label>Eating out</label><select data-log-field="eatout">${opts(['none','light','normal','heavy'],log.eatout,'eatout')}</select></div>
    <div><label>Beers</label><input type="number" min="0" step="1" value="${esc(log.beers)}" data-log-field="beers"></div>
    <div><label>Weight optional</label><input type="number" step="0.1" value="${esc(log.weight)}" data-log-field="weight" placeholder="kg"></div>
    <div class="full"><label>Notes</label><textarea data-log-field="notes" placeholder="Surf/gym, beers, cravings, how you felt...">${esc(log.notes)}</textarea></div>
  </div></details>`; }
function opts(values,current,type){ return values.map(v=>`<option value="${v}" ${v===current?'selected':''}>${esc(labelFor(type,v))}</option>`).join(''); }
function ratingOpts(current){ return `<option value="">Not set</option>`+[1,2,3,4,5].map(x=>`<option value="${x}" ${String(current)===String(x)?'selected':''}>${x}</option>`).join(''); }
function labelFor(type,v){ const maps={morning:{unset:'Not set',skipped:'Skipped',micro:'Very small',small:'Small',medium:'Medium'},training:{none:'None',light:'Light',hard:'Hard'},eatout:{none:'None',light:'Light',normal:'Normal',heavy:'Heavy'}}; return (maps[type]&&maps[type][v])||v||'Not set'; }
function renderHistory(){ const logs=getLogs(); const dates=Object.keys(logs).sort(); const cutoff=addDays(localISODate(new Date()), -historyRange+1); const useDates=dates.filter(d=>historyRange===9999 || d>=cutoff); const stats=historyStats(useDates, logs); return `<section class="card"><div class="section-title"><div><h2>Progress history</h2><p>Stored locally in this browser. Tap a day to edit it.</p></div><select id="rangeSelect" style="width:auto"><option value="7" ${historyRange===7?'selected':''}>7d</option><option value="30" ${historyRange===30?'selected':''}>30d</option><option value="90" ${historyRange===90?'selected':''}>90d</option><option value="9999" ${historyRange===9999?'selected':''}>All</option></select></div><div class="grid four mobile-two">
  <div class="metric"><div class="num">${n(stats.days)}</div><div class="lbl">days logged</div></div><div class="metric"><div class="num">${n(stats.avgCal)}</div><div class="lbl">avg logged kcal</div></div><div class="metric"><div class="num">${n(stats.avgProtein)}g</div><div class="lbl">avg protein</div></div><div class="metric"><div class="num">${n(stats.beers)}</div><div class="lbl">beers</div></div>
  <div class="metric"><div class="num">${n(stats.morningAnchors)}</div><div class="lbl">breakfasts logged</div></div><div class="metric"><div class="num">${n(stats.eatouts)}</div><div class="lbl">eat-out days</div></div><div class="metric"><div class="num">${n(stats.training)}</div><div class="lbl">training days</div></div><div class="metric"><div class="num">${stats.weightChange}</div><div class="lbl">weight trend</div></div>
  </div></section>
  ${renderHistoryPatterns(useDates)}
  <section class="card"><div class="section-title"><div><h2>Trend bars</h2><p>Protein by logged day. This only counts meals you ticked/added.</p></div></div>${useDates.length?useDates.slice(-14).map(d=>renderBar(d, metricsFor(d).protein, 160, 'g')).join(''):'<div class="notice">No logged days yet. Tick meals/check in from Today.</div>'}</section>
  <section class="card"><div class="section-title"><div><h2>Logged days</h2><p>Newest first.</p></div></div><div class="list">${useDates.length?useDates.slice().reverse().map(d=>renderDayLogRow(d, logs[d])).join(''):'<div class="notice">Nothing logged in this range yet.</div>'}</div></section>`; }
function historyStats(dates, logs){ let days=dates.length, cal=0, protein=0, beers=0, anchors=0, eatouts=0, training=0, weights=[]; dates.forEach(d=>{ const l=getLog(d); const m=metricsFor(d); cal+=m.cal; protein+=m.protein; beers+=num(l.beers); if(['micro','small','medium'].includes(l.morning)) anchors++; if(l.eatout && l.eatout!=='none') eatouts++; if(l.training && l.training!=='none') training++; if(l.weight) weights.push({d,w:num(l.weight)}); }); let wt='—'; if(weights.length>=2) wt=(weights[weights.length-1].w-weights[0].w>=0?'+':'')+(weights[weights.length-1].w-weights[0].w).toFixed(1)+'kg'; return {days,avgCal:days?cal/days:0,avgProtein:days?protein/days:0,beers,morningAnchors:anchors,eatouts,training,weightChange:wt}; }
function historyPatterns(dates){ const result={proteinMisses:0,fibreMisses:0,skippedMornings:0,eatoutDays:0,beerDays:0,trainingLowProtein:0}; dates.forEach(d=>{ const l=getLog(d); const m=metricsFor(d); const planned=plannedTotalsFor(planDayForDate(d)); if(m.protein < Math.max(90, planned.protein*.65)) result.proteinMisses++; if(m.fibre < Math.max(18, planned.fibre*.65)) result.fibreMisses++; if(l.morning==='skipped') result.skippedMornings++; if(l.eatout && l.eatout!=='none') result.eatoutDays++; if(num(l.beers)>0) result.beerDays++; if(l.training && l.training!=='none' && m.protein<100) result.trainingLowProtein++; }); return result; }
function renderHistoryPatterns(dates){ const p=historyPatterns(dates); const cards=[['Low protein days',p.proteinMisses,'Days where logged protein was probably low.'],['Low fibre days',p.fibreMisses,'Days where fruit, veg, beans, potato, or muesli may help.'],['Skipped breakfast',p.skippedMornings,'A small breakfast or snack later may help.'],['Eat-out / beer days',p.eatoutDays+p.beerDays,'Use this to plan simple meals around them.'],['Training days with low protein',p.trainingLowProtein,'Add protein and carbs around harder sessions.']]; return `<section class="card"><div class="section-title"><div><h2>Patterns</h2><p>Useful patterns from this range.</p></div></div>${dates.length?`<div class="grid three mobile-two">${cards.map(([title,value,body])=>`<div class="metric"><div class="num">${n(value)}</div><div class="lbl">${esc(title)}</div><div class="muted small" style="margin-top:8px">${esc(body)}</div></div>`).join('')}</div>`:'<div class="notice">Log a few days and this will show practical patterns.</div>'}</section>`; }
function renderBar(date,value,target,suffix){ const pct=Math.max(2,Math.min(100,Math.round(value/target*100))); return `<div class="bar-row"><span class="tiny muted">${date.slice(5)}</span><div class="bar"><span style="width:${pct}%"></span></div><span class="tiny soft">${n(value)}${suffix}</span></div>`; }
function renderDayLogRow(date, log){ const m=metricsFor(date); return `<button class="row" data-edit-date="${date}"><div class="row-left"><div class="row-title">${esc(date)} · ${planDayForDate(date)}</div><div class="muted small">${n(m.cal)} kcal · ${n(m.protein)}g protein · morning ${esc(labelFor('morning',log.morning||'unset'))} · beers ${n(log.beers)}</div></div><span class="badge">Edit</span></button>`; }
function renderWeek(){ const usingAi=!!(Array.isArray(aiMealPlan())&&aiMealPlan().length); const t=template(); return `<section class="card"><div class="section-title"><div><h2>Weekly plan</h2><p>${usingAi?'AI-imported plan is active.':esc(t.focus)}</p></div>${usingAi?'<button class="btn smallbtn danger" data-action="clear-ai-plan">Clear AI plan</button>':''}</div><div class="form-grid"><div><label>Week type</label><select id="templateSelect">${WEEK_TEMPLATES.map(x=>`<option value="${esc(x.id)}" ${x.id===activeTemplate?'selected':''}>${esc(x.name)}</option>`).join('')}</select></div><div><label>Mode</label><input value="${esc(t.tone)}" readonly></div></div><div class="notice" style="margin-top:10px">${esc(t.focus)}</div></section><section class="grid">${DAYS.map(day=>{ const total=plannedTotalsFor(day); const summary=activeWeeklyPlan().find(x=>x.Day===day)||{}; const planned=plannedRecipesFor(day); return `<div class="card flat" style="margin:0"><button data-jump-plan-day="${day}" style="text-align:left;width:100%;background:transparent;border:0;color:inherit;padding:0"><div class="section-title"><div><h2>${day}</h2><p>${esc(t.days[day]||summary['Eating out / flex']||'')}</p></div><span class="badge accent">${n(total.cal)} kcal</span></div><div class="badges"><span class="badge">${esc(summary['Morning pattern']||'')}</span><span class="badge">${esc(summary.Lunch||'')}</span><span class="badge">${esc(summary.Dinner||'')}</span></div><p class="muted small">${esc(summary['What to do if low appetite']||'')}</p></button>${planned.length?`<hr><div class="list">${planned.map(x=>`<div class="row"><div class="row-left"><div class="row-title">${esc(x.title)}</div><div class="muted small">Recipe planned for ${day}</div></div><button class="btn smallbtn danger" data-remove-planned-recipe="${esc(day)}|${esc(x.id)}">Remove</button></div>`).join('')}</div>`:''}</div>`; }).join('')}</section>`; }
function renderPrep(){ const groups=groupBy(DATA.mealPrep, r=>r['Prep session']); return `<section class="card"><div class="section-title"><div><h2>Meal prep</h2><p>Two small component preps. Tick boxes reset with local storage only when you clear them.</p></div><button class="btn smallbtn" data-action="clear-prep">Clear prep ticks</button></div>${Object.entries(groups).map(([name,items])=>`<details class="card flat" open><summary class="recipe-summary"><div><div class="recipe-title">${esc(name)}</div><div class="muted small">${esc(items[0].When||'')}</div></div><span class="chev">▾</span></summary><hr><div class="list">${items.map((r,i)=>{ const k=`prep:${name}:${i}:${r.Component}`; const on=localStorage.getItem(STORE_PREFIX+k)==='1'; return `<label class="row" style="justify-content:flex-start"><input type="checkbox" class="check" ${on?'checked':''} data-simple-check="${esc(k)}"><div><div class="row-title">${esc(r.Component)} · ${esc(r.Amount)}</div><div class="muted small">Use for: ${esc(r['Use for'])}. ${esc(r['Food safety / notes']||'')}</div></div></label>`; }).join('')}</div></details>`).join('')}</section>`; }
function cleanShopItem(item){ return {...item, category:plainCopy(item.category), ingredient:plainCopy(item.ingredient), amount:plainCopy(item.amount), used:plainCopy(item.used), notes:plainCopy(item.notes)}; }
function shopBaseItems(){ return DATA.shoppingList.map((r,i)=>cleanShopItem({id:'base_'+i,category:r.Category||'Other',ingredient:r.Ingredient||'',amount:r['Weekly amount']||'',used:r['Used for']||'',notes:r.Notes||'',custom:false})); }
function generatedShopItems(){ return readJSON('generatedShopItems', []); }
function saveGeneratedShopItems(items){ writeJSON('generatedShopItems', items); }
function shopCustomItems(){ return readJSON('customShopItems', []); }
function saveCustomShopItems(items){ writeJSON('customShopItems', items); }
function isBuyListIngredient(ingredient){ const raw=String(ingredient||'').toLowerCase().trim(); if(!raw || looksLikeInstructionIngredient(raw)) return false; if(/thai\/pub|burger\/chips|pizza\/pub|cafe eggs|sushi\/cafe|eat-out|estimate only/.test(raw)) return false; if(/^(water|cold water|salt|black pepper|cumin|paprika|ground coriander|allspice|allspice or cinnamon|cinnamon|olive oil|soy sauce)$/.test(raw)) return false; if(/\b(iodised salt|cumin|paprika|ground coriander|allspice|cinnamon|olive oil)\b/.test(raw)) return false; return true; }
function pantryItems(){ return readJSON('pantryItems', []); }
function savePantryItems(items){ writeJSON('pantryItems', items); }
function pantryKey(name){ return groceryIngredientName(name).toLowerCase().replace(/[^a-z0-9]+/g,' ').trim(); }
function normalizePantryItem(item){ const ingredient=groceryIngredientName(item.ingredient||item.name||''); if(!isBuyListIngredient(ingredient)) return null; return {id:item.id||'pantry_'+Date.now().toString(36)+'_'+Math.random().toString(36).slice(2,6),ingredient,qty:Math.max(0,num(item.qty??item.count??1)),unit:item.unit||'use',category:item.category||categoryForIngredient(ingredient),notes:item.notes||''}; }
function cleanPantryItems(){ return pantryItems().map(normalizePantryItem).filter(Boolean).sort((a,b)=>a.ingredient.localeCompare(b.ingredient)); }
function pantryCountFor(ingredient){ const key=pantryKey(ingredient); return cleanPantryItems().filter(x=>pantryKey(x.ingredient)===key).reduce((sum,x)=>sum+num(x.qty),0); }
function pantryNeedRemaining(item){ return Math.max(0, num(item.needCount||1)-pantryCountFor(item.ingredient)); }
function savePantryItem(ingredient, qty=1, unit='use'){ const normalized=normalizePantryItem({ingredient,qty,unit}); if(!normalized) return false; const items=cleanPantryItems(); const key=pantryKey(normalized.ingredient); const existing=items.find(x=>pantryKey(x.ingredient)===key); if(existing){ existing.qty+=normalized.qty; if(unit) existing.unit=unit; } else items.push(normalized); savePantryItems(items); return true; }
function adjustPantryItem(id, delta){ const items=cleanPantryItems(); const item=items.find(x=>x.id===id); if(!item) return; item.qty=Math.max(0,num(item.qty)+delta); savePantryItems(items); }
function setPantryItemQty(id, qty){ const items=cleanPantryItems(); const item=items.find(x=>x.id===id); if(!item) return; item.qty=Math.max(0,num(qty)); savePantryItems(items); }
function deletePantryItem(id){ savePantryItems(cleanPantryItems().filter(x=>x.id!==id)); }
function pantryConsumeKey(date, key, ingredient){ return `pantryUse:${date}:${key}:${pantryKey(ingredient)}`; }
function consumePantryIngredient(ingredient){ const items=cleanPantryItems(); const key=pantryKey(ingredient); const item=items.find(x=>pantryKey(x.ingredient)===key && num(x.qty)>0); if(!item) return false; item.qty=Math.max(0,num(item.qty)-1); savePantryItems(items); return true; }
function restorePantryIngredient(ingredient){ return savePantryItem(ingredient, 1, 'use'); }
function applyMealPantryUse(meal, checked, date=selectedDate){ let changed=0; mealShoppingEntries(meal).forEach(rawEntry=>{ const entry=normalizeRangeIngredient(rawEntry); const ingredient=String(entry.ingredient||'').trim(); if(!isBuyListIngredient(ingredient)) return; const key=pantryConsumeKey(date, mealKey(meal), ingredient); if(checked){ if(localStorage.getItem(STORE_PREFIX+key)==='1') return; if(consumePantryIngredient(ingredient)){ localStorage.setItem(STORE_PREFIX+key,'1'); changed++; } } else if(localStorage.getItem(STORE_PREFIX+key)==='1'){ restorePantryIngredient(ingredient); localStorage.removeItem(STORE_PREFIX+key); changed++; } }); return changed; }
function normalizeShopItemDisplay(item){ const entry=normalizeRangeIngredient(item); if(!isBuyListIngredient(entry.ingredient)) return null; return cleanShopItem({...item, ...entry}); }
function shopItems(){ return [...shopBaseItems().map(normalizeShopItemDisplay).filter(Boolean), ...generatedShopItems().map((r,i)=>normalizeShopItemDisplay({id:r.id||('meal_'+i),category:r.category||'Meal plan',ingredient:r.ingredient||r.title||'',amount:r.amount||'',used:r.used||'',notes:r.notes||'',generated:true})).filter(Boolean), ...shopCustomItems().map((r,i)=>normalizeShopItemDisplay({id:r.id||('custom_'+i),category:r.category||'Custom',ingredient:r.ingredient||r.title||'',amount:r.amount||'',used:r.used||'',notes:r.notes||'',custom:true})).filter(Boolean)]; }
function shopItemById(id){ return [...shopRangeItems(), ...shopItems()].find(x=>x.id===id); }
function shopStorageKey(item, field){ return `shop2:${item.id}:${field}`; }
function shopChecked(item){ return localStorage.getItem(STORE_PREFIX+shopStorageKey(item,'checked'))==='1'; }
function shopIncluded(item){ const v=localStorage.getItem(STORE_PREFIX+shopStorageKey(item,'include')); return v===null ? true : v==='1'; }
function shopAmount(item){ const v=localStorage.getItem(STORE_PREFIX+shopStorageKey(item,'amount')); return v===null ? item.amount : v; }
function shopPrefs(){ return {...{filter:'all',hideChecked:false,onlyNeeded:true}, ...readJSON('shopPrefs', {})}; }
function saveShopPrefs(p){ writeJSON('shopPrefs', p); }
function shopKind(item){ const raw=`${item.category} ${item.ingredient} ${item.amount} ${item.used} ${item.notes}`.toLowerCase(); if(item.custom) return 'custom'; if(item.generated) return 'meal'; if(/pantry|jar|box|1kg bag|as needed|iodised|spice|cumin|paprika|coriander|allspice|cinnamon|soy sauce|curry paste|tomato sauce|tahini|muesli|granola|weet-bix|rice|pasta|whey/.test(raw)) return 'pantry'; if(/optional|backup|tinned|frozen|hummus|chickpeas|salmon\/tuna/.test(raw)) return 'backup'; return 'fresh'; }
function shopKindLabel(k){ return {all:'All',fresh:'Fresh run',pantry:'Pantry/top-up',backup:'Backups',meal:'From meals',custom:'Added items'}[k]||k; }
function shopVisibleItems(){ const prefs=shopPrefs(); return shopItems().filter(item=>{ if(prefs.onlyNeeded && !shopIncluded(item)) return false; if(prefs.hideChecked && shopChecked(item)) return false; if(prefs.filter!=='all' && shopKind(item)!==prefs.filter) return false; return true; }); }
function shopCopyText(items){ return items.map(i=>`${i.category} - ${i.ingredient}${shopAmount(i)?` (${shopAmount(i)})`:''}${i.used?` — ${i.used}`:''}`).join('\n'); }
function shopProgress(){ const inc=shopItems().filter(shopIncluded); const bought=inc.filter(shopChecked).length; const pct=inc.length?Math.round(bought/inc.length*100):0; return {included:inc.length,bought,remaining:Math.max(0,inc.length-bought),pct}; }
function categoryForIngredient(name){ const raw=String(name).toLowerCase(); if(/yoghurt|milk|cheese|feta|cottage/.test(raw)) return 'Dairy'; if(/chicken|beef|tuna|salmon|egg|whey|protein/.test(raw)) return 'Protein'; if(/rice|wrap|pita|bread|potato|pasta|oats|muesli|granola|weet/.test(raw)) return 'Carbs'; if(/banana|apple|orange|kiwi|berries|fruit/.test(raw)) return 'Fruit'; if(/salad|tomato|cucumber|onion|garlic|veg|broccoli|beans|spinach|corn/.test(raw)) return 'Veg'; if(/sauce|soy|curry|paste|tahini|lemon|oil|salt|spice|paprika|cumin|hummus|salsa/.test(raw)) return 'Flavour'; return 'Meal plan'; }
function groceryIngredientName(name){ let ingredient=String(name||'').replace(/\s+/g,' ').trim(); const replacements=[[/^use water\b.*$/i,''],[/^thai\/pub\/burrito\/pasta\/sushi dinner\b.*$/i,''],[/^burger\/chips\/pizza\/pub feed\b.*$/i,''],[/^cafe eggs\/sandwich\/bowl style meal\b.*$/i,''],[/^sushi\/cafe wrap\/sandwich\/bowl\b.*$/i,''],[/^cold water\b/i,''],[/^water\b/i,''],[/^salt \+ water\b/i,'salt'],[/^salt and water\b/i,'salt'],[/^lemon$/i,'lemons'],[/^lemon juice\b/i,'lemons'],[/^pita halves\b/i,'Pita breads'],[/^cooked chicken\b/i,'chicken'],[/^cooked rice\b/i,'rice'],[/^rice serve\b/i,'rice'],[/^whey\/protein powder\b/i,'protein powder'],[/^whey\/protein\b/i,'protein powder'],[/^protein powder with milk\b/i,'protein powder'],[/^protein shake\b/i,'protein powder'],[/^garlic tahini yoghurt sauce\b/i,'Greek yoghurt'],[/^garlic yoghurt sauce\b/i,'Greek yoghurt'],[/^greek yoghurt\/cottage cheese\b/i,'Greek yoghurt or cottage cheese'],[/^cottage cheese\/greek yoghurt\b/i,'Greek yoghurt or cottage cheese'],[/^tomato\/cucumber salad\b/i,'tomatoes and cucumber'],[/^cucumber\/tomato\/onion salad\b/i,'tomatoes, cucumber and onion'],[/^tomato\/cucumber\b/i,'tomatoes and cucumber'],[/^soy\/garlic\/ginger\b/i,'ginger'],[/^hummus\/sauce\b/i,'hummus'],[/^cheese\/feta\b/i,'cheese or feta'],[/^corn\/salad\b/i,'corn and salad'],[/^curry paste\/sauce\b/i,'curry paste or sauce'],[/^spinach\/frozen veg\b/i,'spinach or frozen veg'],[/^salad$/i,'salad greens'],[/^salad greens\/spinach$/i,'salad greens or spinach']]; replacements.forEach(([pattern,value])=>{ ingredient=ingredient.replace(pattern,value); }); return ingredient.replace(/\b(cooked|raw|prepared|microwave\/boiled|boiled|fresh|frozen|estimate only|preferred)\b/gi,'').replace(/\s+/g,' ').replace(/\s+,/g,',').trim(); }
function normalizeRangeIngredient(entry){ let ingredient=String(entry.ingredient||'').replace(/\b(if hungry|as needed|to taste)\b/gi,'').replace(/\s+/g,' ').trim(); let amount=String(entry.amount||'').trim(); if(!amount){ const unit='(?:g|kg|mL|ml|L|cup|cups|tbsp|tsp|scoop|scoops|serve|serves|tin|tins|can|cans|pack|packs|slice|slices|piece|pieces)'; const trailing=ingredient.match(new RegExp(`^(.*?)(\\d+(?:\\/\\d+)?(?:\\s*[–-]\\s*\\d+(?:\\.\\d+)?)?\\s*${unit})$`,'i')); const leading=ingredient.match(/^(\d+(?:\/\d+)?(?:\s*[–-]\s*\d+(?:\.\d+)?)?(?:\s*(?:g|kg|mL|ml|L|cup|cups|tbsp|tsp|scoop|scoops|serve|serves|tin|tins|can|cans|pack|packs|slice|slices|piece|pieces))?)\s+(.+)$/i); if(trailing && trailing[1].trim()){ ingredient=trailing[1].trim(); amount=trailing[2].trim(); } else if(leading && leading[2].trim()){ amount=leading[1].trim(); ingredient=leading[2].trim(); } } ingredient=groceryIngredientName(ingredient); return {...entry,ingredient,amount,category:categoryForIngredient(ingredient)}; }
function fallbackMealIngredients(meal){ return String(meal['Portion / ingredients']||meal['Meal / slot']||'').split(/\s+\+\s+|,|;/).map(x=>x.replace(/\b(optional|large|small|medium|cooked|fresh|frozen|estimate only|preferred)\b/gi,'').trim()).filter(x=>x.length>2).slice(0,6).map(x=>({ingredient:x,amount:'',category:categoryForIngredient(x),notes:'Estimated from meal text'})); }
function mealShoppingEntries(meal){ const recipe=allRecipes().find(r=>r.code===meal['Meal Code']); const entries=recipe?recipeIngredientEntries(recipe):[]; return (entries.length?entries:fallbackMealIngredients(meal)).map(entry=>({...entry,used:`${meal.Day} ${meal.Slot}: ${meal['Meal / slot']}`})); }
function rangeDates(){ const days=Math.max(1,Math.min(21,Number(shopRangeDays)||4)); return Array.from({length:days},(_,i)=>addDays(shopRangeStart,i)); }
function shopRangeMeals(){ return rangeDates().flatMap(date=>{ const day=planDayForDate(date); const plan=getPlan(day).map(meal=>({date,day,meal})); const recipes=plannedRecipesFor(day).map(item=>({date,day,recipe:findRecipe(item.id),title:item.title||'Planned recipe'})).filter(x=>x.recipe); return [...plan, ...recipes]; }); }
function shopRangeItems(){ const byKey=new Map(); const addEntry=(rawEntry, used)=>{ const entry=normalizeRangeIngredient(rawEntry); const ingredient=String(entry.ingredient||'').trim(); if(!isBuyListIngredient(ingredient)) return; const category=categoryForIngredient(ingredient); const key=ingredient.toLowerCase(); const existing=byKey.get(key); const amount=entry.amount||''; const cleanUsed=plainCopy(used); if(existing){ existing.needCount=num(existing.needCount)+1; if(amount && !existing.amount.split('; ').includes(amount)) existing.amount=existing.amount?`${existing.amount}; ${amount}`:amount; if(!existing.used.includes(cleanUsed)) existing.used += `; ${cleanUsed}`; } else { byKey.set(key, cleanShopItem({id:'range_'+key.replace(/[^a-z0-9]+/g,'_').replace(/^_|_$/g,'').slice(0,56),category,ingredient,amount,used:cleanUsed,notes:entry.notes||'',range:true,needCount:1})); } };
  shopRangeMeals().forEach(item=>{ if(item.meal){ const label=`${item.date} ${item.day} ${item.meal.Slot}: ${item.meal['Meal / slot']}`; mealShoppingEntries(item.meal).forEach(entry=>addEntry(entry,label)); } else if(item.recipe){ const label=`${item.date} ${item.day}: ${item.title}`; recipeIngredientEntries(item.recipe).forEach(entry=>addEntry(entry,label)); } });
  return [...byKey.values()].sort((a,b)=>a.ingredient.localeCompare(b.ingredient)); }
function refreshGeneratedShopping(){ const byKey=new Map(); const addEntry=(rawEntry, used, note='Generated from weekly meal plan')=>{ const entry=normalizeRangeIngredient(rawEntry); const ingredient=String(entry.ingredient||'').trim(); if(!isBuyListIngredient(ingredient)) return; const key=ingredient.toLowerCase(); const existing=byKey.get(key); if(existing){ if(!existing.used.includes(used)) existing.used += `; ${used}`; if(!existing.amount && entry.amount) existing.amount=entry.amount; } else byKey.set(key,{id:'meal_'+key.replace(/[^a-z0-9]+/g,'_').replace(/^_|_$/g,'').slice(0,48),category:entry.category||categoryForIngredient(ingredient),ingredient,amount:entry.amount||'',used,notes:note}); }; activeMealPlan().forEach(meal=>mealShoppingEntries(meal).forEach(entry=>addEntry(entry, entry.used))); Object.entries(plannedRecipes()).forEach(([day,items])=>items.forEach(item=>{ const r=findRecipe(item.id); if(r) recipeIngredientEntries(r).forEach(entry=>addEntry(entry, `${day} planned recipe: ${r.title}`, 'Generated from planned recipes')); })); saveGeneratedShopItems([...byKey.values()]); toast(`Generated ${byKey.size} meal items`); render(); }
function renderShopRow(item){ const id=esc(item.id); const pantryQty=item.range?pantryCountFor(item.ingredient):0; const remaining=item.range?pantryNeedRemaining(item):null; const meta=[item.used,item.notes].filter(Boolean).join(' · '); return `<div class="row shop-row ${shopChecked(item)?'bought':''}"><input type="checkbox" class="check" ${shopChecked(item)?'checked':''} data-shop-check="${id}" aria-label="Bought ${esc(item.ingredient)}"><div class="row-left"><div class="row-title">${esc(item.ingredient)}${item.custom?' <span class="badge accent">added</span>':''}${item.generated?' <span class="badge accent">meal</span>':''}${item.range&&pantryQty?` <span class="badge">pantry ${n(pantryQty)}/${n(item.needCount||1)}</span>`:''}${item.range&&remaining>0&&num(item.needCount)>1?` <span class="badge warn">buy ${n(remaining)}</span>`:''}</div>${meta?`<div class="muted small">${esc(meta)}</div>`:''}</div><div class="shop-actions compact"><input class="shop-qty" value="${esc(shopAmount(item))}" data-shop-amount="${id}" aria-label="Quantity for ${esc(item.ingredient)}">${item.range?`<button class="btn smallbtn" data-pantry-from-shop="${id}">Have</button>`:''}<label class="mini-check"><input type="checkbox" ${shopIncluded(item)?'checked':''} data-shop-include="${id}"> Need</label>${item.custom?`<button class="btn smallbtn danger" data-delete-shop-item="${id}">Delete</button>`:''}</div></div>`; }
function renderPantryPanel(){ const pantry=cleanPantryItems(); return `<details class="shop-advanced pantry-panel" open><summary class="recipe-summary"><div><div class="recipe-title">Pantry</div><div class="muted small">${pantry.length?`${pantry.length} stocked item${pantry.length===1?'':'s'}`:'Add what you already have.'}</div></div><span class="chev">▾</span></summary><hr><div class="form-grid"><div><label>Item</label><input id="pantryNewIngredient" placeholder="e.g. Rice"></div><div><label>Have</label><input id="pantryNewQty" type="number" min="0" step="1" value="1"></div><div class="full"><button class="btn primary" data-action="save-pantry-item">Add to pantry</button></div></div>${pantry.length?`<hr><div class="list">${pantry.map(item=>`<div class="row pantry-row"><div class="row-left"><div class="row-title">${esc(item.ingredient)}</div><div class="muted small">${esc(item.category)} · ${n(item.qty)} ${esc(item.unit||'use')}${item.notes?` · ${esc(item.notes)}`:''}</div></div><div class="shop-actions compact"><button class="btn smallbtn" data-pantry-step="${esc(item.id)}|-1">−</button><input class="shop-qty" type="number" min="0" step="1" value="${esc(item.qty)}" data-pantry-qty="${esc(item.id)}" aria-label="Pantry count for ${esc(item.ingredient)}"><button class="btn smallbtn" data-pantry-step="${esc(item.id)}|1">+</button><button class="btn smallbtn danger" data-delete-pantry="${esc(item.id)}">Delete</button></div></div>`).join('')}</div>`:''}</details>`; }
function renderShop(){
  const prefs=shopPrefs();
  const all=shopItems();
  const visible=shopVisibleItems();
  const groups=groupBy(visible, r=>r.category);
  const progress=shopProgress();
  const kinds=['all','fresh','pantry','backup','meal','custom'];
  const kindCounts=kinds.reduce((a,k)=>{ a[k]=k==='all'?all.filter(shopIncluded).length:all.filter(x=>shopIncluded(x)&&shopKind(x)===k).length; return a; },{});
  const recipeOptions=allRecipes().map(r=>`<option value="${esc(r.custom?'custom:'+r.id:(r.code||r.id))}">${esc(r.title||r.code||'Recipe')}</option>`).join('');
  const dates=rangeDates();
  const rangeItems=shopRangeItems();
  const buyRange=rangeItems.filter(item=>shopIncluded(item)&&pantryNeedRemaining(item)>0);
  const visibleRange=buyRange.filter(item=>!(prefs.hideChecked && shopChecked(item)));
  const boughtRange=buyRange.filter(shopChecked).length;
  const pantryCovered=rangeItems.filter(item=>shopIncluded(item)&&pantryNeedRemaining(item)===0).length;
  const rangeProgress={included:buyRange.length,bought:boughtRange,remaining:Math.max(0,buyRange.length-boughtRange),pct:buyRange.length?Math.round(boughtRange/Math.max(1,buyRange.length)*100):0};
  const rangeMeals=shopRangeMeals();
  const progressBar=`<div class="progress-track"><span style="width:${progress.pct}%"></span></div>`;
  const rangeProgressBar=`<div class="progress-track"><span style="width:${rangeProgress.pct}%"></span></div>`;
  return `<section class="card shop-page"><div class="section-title"><div><h2>Groceries</h2><p>Ingredients for planned meals, ${esc(dates[0])} to ${esc(dates[dates.length-1])}.</p></div><div class="badges"><button class="btn smallbtn primary" data-action="copy-shop">Copy list</button></div></div>
  <div class="form-grid"><div><label>Start date</label><input type="date" id="shopRangeStart" value="${esc(shopRangeStart)}"></div><div><label>Days</label><select id="shopRangeDays"><option value="4" ${shopRangeDays===4?'selected':''}>4 days</option><option value="7" ${shopRangeDays===7?'selected':''}>7 days</option><option value="10" ${shopRangeDays===10?'selected':''}>10 days</option><option value="14" ${shopRangeDays===14?'selected':''}>14 days</option></select></div><div class="full badges"><button class="btn smallbtn" data-action="shop-range-selected">Use selected day</button><button class="btn smallbtn" data-shop-range-days="4">4 days</button><button class="btn smallbtn" data-shop-range-days="7">7 days</button></div></div>
  <hr>${renderPantryPanel()}
  <hr><div class="grid four mobile-two shop-progress"><div class="metric"><div class="num">${rangeProgress.remaining}</div><div class="lbl">left to buy</div></div><div class="metric"><div class="num">${rangeProgress.bought}/${rangeProgress.included}</div><div class="lbl">bought</div></div><div class="metric"><div class="num">${pantryCovered}</div><div class="lbl">covered by pantry</div></div><div class="metric"><div class="num">${rangeMeals.length}</div><div class="lbl">planned meals</div></div></div><div style="margin:10px 0 12px">${rangeProgressBar}</div>
  <div class="shop-list">${visibleRange.length?`<div class="list">${visibleRange.map(renderShopRow).join('')}</div>`:'<div class="notice">No ingredients to buy for this range. Pantry may already cover it.</div>'}</div>
  <details class="shop-advanced"><summary class="recipe-summary"><div><div class="recipe-title">More shopping tools</div><div class="muted small">Filters, generated meal items, and custom additions.</div></div><span class="chev">▾</span></summary><hr>
    <div class="grid two mobile-two shop-progress"><div class="metric"><div class="num">${progress.remaining}</div><div class="lbl">saved-list items left</div></div><div class="metric"><div class="num">${progress.bought}/${progress.included}</div><div class="lbl">saved-list bought</div></div></div><div style="margin:10px 0 12px">${progressBar}</div>
    <div class="tool-panel"><div class="tool-title">Views</div><div class="shop-toolbar">${kinds.map(k=>`<button class="shop-filter ${prefs.filter===k?'active':''}" data-shop-filter="${k}">${esc(shopKindLabel(k))} <span class="muted">${kindCounts[k]||0}</span></button>`).join('')}</div></div>
    <div class="tool-panel"><div class="tool-title">Saved list</div><div class="shop-list">${Object.keys(groups).length?Object.entries(groups).map(([cat,items])=>`<details class="shop-group"><summary class="recipe-summary"><div class="recipe-title">${esc(cat)} <span class="muted small">${items.length} item${items.length===1?'':'s'}</span></div><span class="chev">▾</span></summary><hr><div class="list">${items.map(renderShopRow).join('')}</div></details>`).join(''):'<div class="notice">Nothing in this saved-list view.</div>'}</div></div>
    <div class="tool-panel"><div class="tool-title">List controls</div><div class="shop-toolbar"><label class="mini-check"><input type="checkbox" ${prefs.hideChecked?'checked':''} data-shop-pref="hideChecked"> Hide bought</label><label class="mini-check"><input type="checkbox" ${prefs.onlyNeeded?'checked':''} data-shop-pref="onlyNeeded"> Only needed</label><button class="btn smallbtn primary" data-action="generate-meal-shopping">Generate from meals</button><button class="btn smallbtn" data-action="copy-shop-all">Copy all needed</button><button class="btn smallbtn" data-action="clear-shop">Clear bought</button><button class="btn smallbtn" data-action="reset-shop-view">Reset view</button></div></div>
    <div class="tool-panel"><div class="tool-title">Add item</div><div class="form-grid"><div><label>Item</label><input id="shopNewIngredient" placeholder="e.g. Halloumi"></div><div><label>Amount</label><input id="shopNewAmount" placeholder="e.g. 1 pack"></div><div><label>Category</label><input id="shopNewCategory" placeholder="e.g. Extras"></div><div><label>Used for</label><input id="shopNewUsed" placeholder="e.g. Saturday dinner"></div><div class="full"><label>Notes</label><input id="shopNewNotes" placeholder="Optional notes"></div><div class="full"><button class="btn primary" data-action="save-shop-item">Add shopping item</button></div></div></div>
    <div class="tool-panel"><div class="tool-title">Recipe ingredients</div><div class="form-grid"><div class="full"><label>Recipe</label><select id="shopRecipeSelect">${recipeOptions}</select></div><div class="full"><button class="btn" data-action="add-recipe-shopping">Add selected recipe ingredients</button></div></div></div>
  </details></section>`;
}
function renderRecipes(){ const recipes=allRecipes().filter(r=>!recipeFilter || (r.title||'').toLowerCase().includes(recipeFilter.toLowerCase())); return `<section class="card"><div class="section-title"><div><h2>Recipes</h2><p>Add recipes, then log them against any day.</p></div><button class="btn primary smallbtn" data-action="toggle-recipe-form">Add recipe</button></div><input id="recipeSearch" placeholder="Search recipes" value="${esc(recipeFilter)}"><div id="recipeFormWrap" class="${editingRecipeId?'':'hide'}">${renderRecipeForm()}</div><hr>${renderRecipeJsonImport()}</section>${renderAddOnMeals()}<section class="grid">${recipes.map(renderRecipeCard).join('')}</section>`; }
function renderRecipeForm(){ const edit=editingRecipeId?customRecipes().find(r=>r.id===editingRecipeId):null; const title=edit?'Edit recipe':'New recipe'; const selectedType=edit?.type||'Dinner'; const typeOpt=t=>`<option ${selectedType===t?'selected':''}>${t}</option>`; return `<div class="card flat" style="margin-top:12px"><h2>${title}</h2><div class="form-grid"><div class="full"><label>Name</label><input data-recipe-field="title" value="${esc(edit?.title||'')}" placeholder="Chicken souvlaki wraps"></div><div><label>Type</label><select data-recipe-field="type">${['Dinner','Lunch','Breakfast','Snack','Backup'].map(typeOpt).join('')}</select></div><div><label>Tags/use case</label><input data-recipe-field="tags" value="${esc(edit?.tags||'')}" placeholder="training, low appetite, beer-night"></div><div><label>Serves</label><input data-recipe-field="serves" value="${esc(edit?.serves||'')}" placeholder="3"></div><div><label>Calories / serve</label><input data-recipe-field="calories" type="number" value="${esc(edit?.calories||'')}"></div><div><label>Protein g</label><input data-recipe-field="protein" type="number" value="${esc(edit?.protein||'')}"></div><div><label>Carbs g</label><input data-recipe-field="carbs" type="number" value="${esc(edit?.carbs||'')}"></div><div><label>Fat g</label><input data-recipe-field="fat" type="number" value="${esc(edit?.fat||'')}"></div><div><label>Fibre g</label><input data-recipe-field="fibre" type="number" value="${esc(edit?.fibre||'')}"></div><div class="full"><label>Ingredients</label><textarea data-recipe-field="ingredients" placeholder="One per line: item - amount - category - notes">${esc(edit?.ingredients||'')}</textarea></div><div class="full"><label>Method</label><textarea data-recipe-field="method" placeholder="One step per line">${esc(edit?.method||'')}</textarea></div><div class="full"><label>Notes</label><textarea data-recipe-field="notes" placeholder="Meal prep notes, when to use it, swaps...">${esc(edit?.notes||'')}</textarea></div><div class="full badges"><button class="btn primary" data-action="save-recipe">${edit?'Update recipe':'Save recipe locally'}</button>${edit?'<button class="btn" data-action="cancel-recipe-edit">Cancel</button>':''}</div></div></div>`; }
function renderRecipeJsonImport(){ return `<details class="card flat"><summary class="recipe-summary"><div><div class="recipe-title">AI recipe import</div><div class="muted small">Paste one recipe, many recipes, or add-on meals.</div></div><span class="chev">▾</span></summary><hr><div class="badges"><button class="btn smallbtn" data-action="copy-recipe-import-format">Copy format</button><button class="btn smallbtn" data-action="fill-recipe-import-example">Paste example</button></div><textarea id="recipeImportText" style="margin-top:10px" placeholder='{"eatRepeatRecipeImport":{"recipes":[],"addOnMeals":[]}}'></textarea><div class="badges" style="margin-top:10px"><button class="btn primary" data-action="import-recipe-json">Import recipes/add-ons</button></div></details>`; }
function renderAddOnMeals(){ const addOns=allQuickMealPresets(); return `<section class="card"><div class="section-title"><div><h2>Add-on meals</h2><p>Small meals that appear in Today quick add.</p></div></div><div class="grid three mobile-two">${addOns.map(m=>`<div class="metric"><div class="lbl">${esc(m.title)}</div><div class="num">${n(m.calories)} kcal</div><div class="muted small">${n(m.protein)}g protein · ${n(m.fibre)}g fibre${m.tags?` · ${esc(m.tags)}`:''}</div><div class="badges" style="margin-top:8px"><button class="btn smallbtn" data-quick-preset="${esc(m.id)}">Add to day</button>${m.custom?`<button class="btn smallbtn danger" data-delete-addon="${esc(m.id)}">Delete</button>`:''}</div></div>`).join('')}</div></section>`; }
function renderRecipeCard(r){ const nu=recipeNutrition(r); const ing=recipeIngredients(r); const method=recipeMethod(r); const id=recipeLookupId(r); return `<details class="card recipe-card"><summary><div class="recipe-summary"><div><div class="recipe-title">${esc(r.title)} ${r.custom?'<span class="badge accent">custom</span>':''}</div><div class="muted small">${n(nu.cal)} kcal · ${n(nu.protein)}g protein · ${n(nu.fibre)}g fibre</div></div><span class="chev">▾</span></div></summary><hr><p class="soft small">${esc(r.subtitle||r.portion||r.notes||'')}</p><div class="badges"><span class="badge accent">${n(nu.cal)} kcal</span><span class="badge">${n(nu.protein)}g protein</span><span class="badge">${n(nu.carbs)}g carbs</span><span class="badge">${n(nu.fat)}g fat</span><span class="badge">${n(nu.fibre)}g fibre</span>${r.tags?`<span class="badge">${esc(r.tags)}</span>`:''}</div><hr><h3>Ingredients</h3><div class="badges">${ing.slice(0,24).map(x=>`<span class="badge">${esc(x)}</span>`).join('')}</div><h3>Method</h3><ol class="soft small">${method.map(x=>`<li>${esc(x)}</li>`).join('')}</ol><div class="badges"><button class="btn smallbtn primary" data-add-recipe-to-day="${esc(id)}">Add to ${esc(selectedDate)}</button><button class="btn smallbtn" data-plan-recipe="${esc(id)}">Plan this ${esc(planDayForDate(selectedDate))}</button><button class="btn smallbtn" data-add-recipe-shopping="${esc(id)}">Add to shopping</button><button class="btn smallbtn" data-copy-recipe-shop="${esc(id)}">Copy ingredients</button><button class="btn smallbtn" data-duplicate-recipe="${esc(id)}">Duplicate</button>${r.custom?`<button class="btn smallbtn" data-edit-recipe="${esc(r.id)}">Edit</button><button class="btn smallbtn danger" data-delete-recipe="${esc(r.id)}">Delete</button>`:''}</div></details>`; }
function renderFlex(){ const groups=groupBy(DATA.addOns, r=>r['Use case']); return `<section class="card"><div class="section-title"><div><h2>Flexible days</h2><p>Simple notes for eating out, beers and training.</p></div></div><div class="grid two"><div class="notice"><b>Skipped breakfast</b><br>Have something small later: milk + banana, yoghurt, or protein. Do not skip lunch just because breakfast was light.</div><div class="notice"><b>Eating out tonight</b><br>Keep lunch protein-heavy, skip random snacks if not hungry, and log the eat-out level.</div><div class="notice"><b>Beer night</b><br>Keep protein earlier. Beers are logged at about 170 kcal each.</div><div class="notice"><b>Hard training</b><br>Add banana, rice, potatoes or shake around the session if energy is flat.</div></div></section><section class="card"><h2>Add-ons</h2>${Object.entries(groups).map(([use,items])=>`<details class="card flat"><summary class="recipe-summary"><div class="recipe-title">${esc(use)}</div><span class="chev">▾</span></summary><hr><div class="list">${items.map(r=>`<div class="row"><div><div class="row-title">${esc(r['Add / remove'])}</div><div class="muted small">${n(r.Calories)} kcal · ${n(r['Protein g'])}g protein · ${esc(r['How to use'])}</div></div></div>`).join('')}</div></details>`).join('')}</section>`; }
function renderSettings(){ const logs=getLogs(); const customs=customRecipes(); const generated=generatedShopItems(); const hasAiPlan=Array.isArray(aiMealPlan())&&aiMealPlan().length; return `<section class="card"><div class="section-title"><div><h2>Settings + backup</h2><p>Everything is stored only in this browser using local storage.</p></div></div><div class="grid two"><button class="btn primary" data-action="export-data">Export backup JSON</button><label class="btn" style="text-align:center">Import backup<input type="file" id="importFile" accept="application/json" style="display:none"></label><button class="btn" data-action="export-ai-handoff">Copy AI request</button><button class="btn" data-action="copy-friend-pack">Copy friend starter pack</button><button class="btn danger" data-action="clear-logs">Clear daily logs</button><button class="btn danger" data-action="clear-recipes">Clear custom recipes</button>${hasAiPlan?'<button class="btn danger" data-action="clear-ai-plan">Clear AI plan</button>':''}</div><hr><div class="grid four mobile-two"><div class="metric"><div class="num">${n(Object.keys(logs).length)}</div><div class="lbl">logged days</div></div><div class="metric"><div class="num">${n(customs.length)}</div><div class="lbl">custom recipes</div></div><div class="metric"><div class="num">${n(generated.length)}</div><div class="lbl">meal list items</div></div><div class="metric"><div class="num">${esc(template().name)}</div><div class="lbl">week type</div></div></div><hr><details class="card flat" open><summary class="recipe-summary"><div><div class="recipe-title">AI request</div><div class="muted small">Copy a focused local JSON request for a useful food-planning task.</div></div><span class="chev">▾</span></summary><hr><div class="form-grid"><div class="full"><label>Task</label><select id="aiRequestSelect">${Object.keys(AI_REQUESTS).map(k=>`<option value="${esc(k)}" ${k===activeAiRequest?'selected':''}>${esc({week:'Fix next week',pantry:'3 pantry dinners',low:'Low appetite options',training:'Training week',friend:'Friend starter'}[k])}</option>`).join('')}</select></div><div class="full"><div class="notice">${esc(AI_REQUESTS[activeAiRequest]||AI_REQUESTS.week)}</div></div><div class="full"><button class="btn primary" data-action="export-ai-handoff">Copy AI request</button></div></div></details><hr><details class="card flat"><summary class="recipe-summary"><div><div class="recipe-title">AI import</div><div class="muted small">Paste JSON from an assistant to add recipes, shopping items, or a meal plan.</div></div><span class="chev">▾</span></summary><hr><textarea id="aiImportText" placeholder='{"recipes":[],"shoppingItems":[],"mealPlan":[],"weeklyPlan":[]}'></textarea><div class="badges" style="margin-top:10px"><button class="btn primary" data-action="import-ai-json">Import AI JSON</button><button class="btn" data-action="fill-ai-template">Example format</button></div></details><hr><div class="notice">Friend sharing is local JSON only: recipes, week type, weekly plan, and shopping context without private day logs.</div></section>`; }
