    <div class="full"><label>Task</label><select id="aiRequestSelect">${Object.entries(AI_REQUESTS).map(([k,v])=>`<option value="${esc(k)}" ${k===activeAiRequest?'selected':''}>${esc(v.label)}</option>`).join('')}</select></div>
