function recipeImportTemplateObject(){ return {eatRepeatRecipeImport:{recipes:[{title:'Chicken souvlaki wraps',type:'Dinner',tags:'training, easy lunch leftovers',serves:'3',calories:640,protein:45,carbs:62,fat:18,fibre:7,ingredients:[{ingredient:'Chicken thigh',amount:'600g',category:'Protein',notes:'Can use breast'},{ingredient:'Wraps',amount:'3 large',category:'Carbs'},{ingredient:'Greek yoghurt',amount:'200g',category:'Dairy',notes:'Sauce'}],method:['Cook seasoned chicken.','Mix yoghurt sauce.','Serve in wraps with salad.'],notes:'Practical recurring recipe'}],addOnMeals:[{title:'Cottage cheese + fruit',tags:'snack, low appetite',calories:260,protein:28,carbs:28,fat:4,fibre:4,notes:'Quick add option for light days'}]}}; }
function recipeImportFormatText(){ return ['Turn recipe notes, a pasted recipe, or multiple recipes into JSON for Eat Repeat.','Return JSON only. No markdown fences or extra text.','Use this exact wrapper when possible: eatRepeatRecipeImport.','You may include one recipe, many recipes, one add-on meal, or many add-on meals.','Recipes are full recipe cards. Add-on meals are quick macro meals that appear in Today quick add.','','Expected JSON format:','```json',JSON.stringify(recipeImportTemplateObject(),null,2),'```','','Field notes:','recipes[].ingredients may be an array of objects or lines like "item - amount - category - notes".','recipes[].method may be an array of steps or a newline-separated string.','addOnMeals need title, calories, protein, carbs, fat, fibre. Tags and notes are optional.','Keep estimates realistic and use per-serve macros.'].join('\n'); }
function normalizeAddOnMeal(x){ const id=x.id||'addon_'+Date.now().toString(36)+'_'+Math.random().toString(36).slice(2,6); return {id,title:x.title||x.name||'Add-on meal',tags:Array.isArray(x.tags)?x.tags.join(', '):(x.tags||''),calories:num(x.calories||x.cal||x.macrosPerServe?.calories),protein:num(x.protein||x.macrosPerServe?.protein),carbs:num(x.carbs||x.macrosPerServe?.carbs),fat:num(x.fat||x.macrosPerServe?.fat),fibre:num(x.fibre||x.fiber||x.macrosPerServe?.fibre||x.macrosPerServe?.fiber),notes:x.notes||x.description||'',createdAt:x.createdAt||new Date().toISOString(),updatedAt:new Date().toISOString(),custom:true}; }
function recipeImportData(payload){ const data=payload?.eatRepeatRecipeImport||payload?.eatRepeatAiUpdate||payload?.update||payload; const recipes=Array.isArray(data)?data:(data.recipe?[data.recipe]:(data.recipes||data.customRecipes||[])); const addOns=data.addOnMeals||data.addOns||data.quickMeals||data.quickAddMeals||[]; return {recipes:Array.isArray(recipes)?recipes:[], addOns:Array.isArray(addOns)?addOns:[]}; }
function importRecipeJsonText(){ try{ const text=document.getElementById('recipeImportText')?.value||''; if(!text.trim()) return toast('Paste recipe JSON first'); const data=recipeImportData(JSON.parse(text)); const recipes=data.recipes.map(normalizeAiRecipe).filter(x=>x.title); const addOns=data.addOns.map(normalizeAddOnMeal).filter(x=>x.title); if(!recipes.length && !addOns.length) throw new Error('No recipes or addOnMeals found'); if(recipes.length) saveCustomRecipes([...customRecipes(), ...recipes]); if(addOns.length) saveCustomAddOns([...customAddOns(), ...addOns]); toast(`Imported ${[recipes.length?`${recipes.length} recipe${recipes.length===1?'':'s'}`:'', addOns.length?`${addOns.length} add-on${addOns.length===1?'':'s'}`:''].filter(Boolean).join(', ')}`); render(); } catch(err){ alert('Recipe import failed: '+err.message); } }
function copyRecipeImportFormat(){ copyText(recipeImportFormatText(), 'Recipe import format'); }
function fillRecipeImportExample(){ const el=document.getElementById('recipeImportText'); if(el) el.value=JSON.stringify(recipeImportTemplateObject(),null,2); }
function aiHandoffPayloadV3(){ const dates=Object.keys(getLogs()).sort().slice(-30); const req=aiRequestDef(); return {format:'eat-repeat-ai-handoff',version:4,exportedAt:new Date().toISOString(),task:{id:activeAiRequest,label:req.label,prompt:req.prompt,deliverable:req.deliverable,agentInstructions:aiAgentInstructions()},agentGuidance:{useUserData:'The import should be based on the user data in currentAppData and the baseline data in seedReference.',responseGuide:AI_AGENT_RESPONSE_GUIDE},userDataSummary:aiUserDataSummary(dates),importContract:AI_IMPORT_CONTRACT,exampleImport:aiImportTemplateObject(),currentAppData:{selectedDate,historyRange,activeTemplate:template(),plannedRecipes:plannedRecipes(),historyPatterns:historyPatterns(dates),recommendation:recommendationFor(selectedDate),logs:getLogs(),customRecipes:customRecipes(),customAddOns:customAddOns(),customShopItems:shopCustomItems(),generatedShopItems:generatedShopItems(),pantryItems:cleanPantryItems(),aiMealPlan:aiMealPlan(),aiWeeklyPlan:aiWeeklyPlan()},seedReference:{templates:WEEK_TEMPLATES,weeklyPlan:DATA.weeklyPlan,mealPlan:DATA.mealPlan,recipes:DATA.recipes,shoppingList:DATA.shoppingList,addOns:DATA.addOns}}; }
function compactRecipeForAi(r){ const nu=recipeNutrition(r); return {id:recipeLookupId(r),title:r.title,type:r.type||'',tags:r.tags||'',calories:nu.cal,protein:nu.protein,carbs:nu.carbs,fat:nu.fat,fibre:nu.fibre,ingredients:recipeIngredients(r).slice(0,20),method:recipeMethod(r).slice(0,8),notes:r.notes||r.subtitle||r.portion||''}; }
function compactMealPlanRow(r){ return {Day:r.Day,Slot:r.Slot,'Meal Code':r['Meal Code'],'Meal / slot':r['Meal / slot'],'Portion / ingredients':r['Portion / ingredients'],Calories:r.Calories,'Protein g':r['Protein g'],'Carbs g':r['Carbs g'],'Fat g':r['Fat g'],'Fibre g':r['Fibre g']}; }
function compactShopItemForAi(x){ return {ingredient:x.ingredient||x.Ingredient||'',amount:x.amount||x['Weekly amount']||'',category:x.category||x.Category||'',used:x.used||x['Used for']||'',notes:x.notes||x.Notes||''}; }
function compactTemplateForAi(t){ return {id:t.id,name:t.name,tone:t.tone,focus:t.focus,days:t.id===activeTemplate?t.days:undefined}; }
function aiPromptContext(dates){ const generated=generatedShopItems().map(compactShopItemForAi); const customShop=shopCustomItems().map(compactShopItemForAi); const generatedLimit=40; return {format:'eat-repeat-ai-task-context',version:1,exportedAt:new Date().toISOString(),task:aiHandoffPayloadV3().task,userDataSummary:aiUserDataSummary(dates),currentUserData:{selectedDate,historyRange,activeTemplate:template(),historyPatterns:historyPatterns(dates),recommendation:recommendationFor(selectedDate),logs:getLogs(),plannedRecipes:plannedRecipes(),customRecipes:customRecipes().map(compactRecipeForAi),customAddOns:customAddOns(),customShopItems:customShop,generatedShopItems:{count:generated.length,items:generated.slice(0,generatedLimit),omitted:Math.max(0,generated.length-generatedLimit)},pantryItems:cleanPantryItems(),aiMealPlan:aiMealPlan(),aiWeeklyPlan:aiWeeklyPlan()},baselineReference:{templates:WEEK_TEMPLATES.map(compactTemplateForAi),weeklyPlan:activeWeeklyPlan(),mealPlan:activeMealPlan().map(compactMealPlanRow),recipes:allRecipes().map(compactRecipeForAi),shoppingList:DATA.shoppingList.map(compactShopItemForAi),addOns:DATA.addOns},notes:['This is compact task context for the normal copy/download request. Use Copy raw context only if you need the complete uncompressed handoff.','Generated shopping items are capped because they are repetitive; use the count and examples to infer shopping style.']}; }
function aiPromptText(){ const dates=Object.keys(getLogs()).sort().slice(-30); const payload=aiHandoffPayloadV3(); const context=aiPromptContext(dates); return ['You are helping update my local Eat Repeat meal planner.','',`Task: ${payload.task.label}`,payload.task.prompt,'','Use the user data already included below. Start from existing logs, recipes, shopping items, week type, planned recipes, generated shopping list, and any AI plans. Do not make generic suggestions that ignore this data.','','IMPORTANT: do not return this context JSON. Create a new import response using the exact JSON shape below. Replace the example values with useful values based on the user data.','','Required JSON response example. Return this shape only, with whichever fields are useful:','```json',aiImportTemplateV2(),'```','','User data summary:',JSON.stringify(context.userDataSummary,null,2),'',`Instructions from the user:\n${payload.task.agentInstructions || 'No extra instructions.'}`,'',`Agent response guide:\n${payload.agentGuidance.responseGuide.map((x,i)=>`${i+1}. ${x}`).join('\n')}`,'','Return ONLY JSON that this app can import. Do not include markdown fences, prose, or analysis in the final answer.','Use this exact top-level wrapper when possible: eatRepeatAiUpdate.','Only include fields that should be added or overridden.','',`Import contract:\n${JSON.stringify(AI_IMPORT_CONTRACT,null,2)}`,'',`Task-focused user/app context:\n${JSON.stringify(context,null,2)}`].join('\n'); }
function exportAiRequest(){ copyText(aiPromptText(), 'AI request'); }
function downloadAiRequest(){ downloadTextFile(`eat-repeat-ai-request-${localISODate(new Date())}.txt`, aiPromptText(), 'text/plain'); }
function copyAiContext(){ copyText(JSON.stringify(aiHandoffPayloadV3(),null,2), 'AI raw context'); }
function copyAiImportFormat(){ copyText(aiImportTemplateV2(), 'AI import format'); }
function normalizeAiRecipe(r){ const id=r.id||Date.now().toString(36)+Math.random().toString(36).slice(2,6); return {id,code:r.code||`AI_${id}`,custom:true,title:r.title||r.name||'AI recipe',type:r.type||'Dinner',tags:Array.isArray(r.tags)?r.tags.join(', '):(r.tags||''),serves:r.serves||r.makesServes||'',calories:num(r.calories||r.macrosPerServe?.calories),protein:num(r.protein||r.macrosPerServe?.protein),carbs:num(r.carbs||r.macrosPerServe?.carbs),fat:num(r.fat||r.macrosPerServe?.fat),fibre:num(r.fibre||r.macrosPerServe?.fibre),ingredients:Array.isArray(r.ingredients)?r.ingredients.map(x=>typeof x==='string'?x:`${x.name||x.ingredient||''}${x.amount?` - ${x.amount}`:''}${x.category?` - ${x.category}`:''}`).join('\n'):(r.ingredients||''),ingredientList:Array.isArray(r.ingredients)?r.ingredients.map(normalizeRecipeIngredient).filter(Boolean):undefined,method:Array.isArray(r.method)?r.method.map(x=>typeof x==='string'?x:(x.text||'')).join('\n'):(r.method||''),notes:r.notes||r.description||'',createdAt:r.createdAt||new Date().toISOString(),updatedAt:new Date().toISOString()}; }
function mergeMealPlan(incoming){ const full=DAYS.every(day=>incoming.some(row=>row.Day===day)); if(full) return incoming; const merged=[...DATA.mealPlan]; incoming.forEach(row=>{ const idx=merged.findIndex(x=>x.Day===row.Day && (x.Slot===row.Slot || x['Meal Code']===row['Meal Code'])); if(idx>=0) merged[idx]={...merged[idx],...row}; else merged.push(row); }); return merged; }
function mergeWeeklyPlan(incoming){ const full=DAYS.every(day=>incoming.some(row=>row.Day===day)); if(full) return incoming; const merged=[...DATA.weeklyPlan]; incoming.forEach(row=>{ const idx=merged.findIndex(x=>x.Day===row.Day); if(idx>=0) merged[idx]={...merged[idx],...row}; else merged.push(row); }); return merged; }
function importAiPayload(payload){ const data=payload.eatRepeatAiUpdate||payload.foodOsAiUpdate||payload.eatRepeatRecipeImport||payload.update||payload; let changed=[]; if(Array.isArray(data.recipes)||Array.isArray(data.customRecipes)){ const incoming=(data.recipes||data.customRecipes).map(normalizeAiRecipe); saveCustomRecipes([...customRecipes(),...incoming]); changed.push(`${incoming.length} recipes`); } if(Array.isArray(data.addOnMeals)||Array.isArray(data.addOns)||Array.isArray(data.quickMeals)){ const incoming=(data.addOnMeals||data.addOns||data.quickMeals).map(normalizeAddOnMeal); saveCustomAddOns([...customAddOns(),...incoming]); changed.push(`${incoming.length} add-ons`); } if(Array.isArray(data.shoppingItems)||Array.isArray(data.customShopItems)){ const incoming=(data.shoppingItems||data.customShopItems).map((x,i)=>({id:x.id||'custom_ai_'+Date.now().toString(36)+'_'+i,ingredient:x.ingredient||x.name||x.title||'',amount:x.amount||'',category:x.category||'AI import',used:x.used||x.source||'AI import',notes:x.notes||''})).filter(x=>x.ingredient); saveCustomShopItems([...shopCustomItems(),...incoming]); changed.push(`${incoming.length} shopping items`); } if(Array.isArray(data.generatedShopItems)){ saveGeneratedShopItems(data.generatedShopItems); changed.push(`${data.generatedShopItems.length} generated shopping items`); } if(data.plannedRecipes && typeof data.plannedRecipes==='object'){ savePlannedRecipes(data.plannedRecipes); changed.push('planned recipes'); } if(data.activeTemplate && WEEK_TEMPLATES.some(t=>t.id===data.activeTemplate)){ activeTemplate=data.activeTemplate; localStorage.setItem(STORE_PREFIX+'activeTemplate', activeTemplate); changed.push('template'); } if(Array.isArray(data.mealPlan)&&data.mealPlan.length){ saveAiMealPlan(mergeMealPlan(data.mealPlan)); changed.push('meal plan override'); } if(Array.isArray(data.weeklyPlan)&&data.weeklyPlan.length){ saveAiWeeklyPlan(mergeWeeklyPlan(data.weeklyPlan)); changed.push('weekly plan override'); } if(!changed.length) throw new Error('No recipes, addOnMeals, shoppingItems, mealPlan, weeklyPlan, or plannedRecipes found'); toast(`Imported ${changed.join(', ')}`); render(); }
function importAiText(){ try{ const text=document.getElementById('aiImportText')?.value||''; if(!text.trim()) return toast('Paste AI JSON first'); importAiPayload(JSON.parse(text)); } catch(err){ alert('AI import failed: '+err.message); } }
function importData(file){ const reader=new FileReader(); reader.onload=()=>{ try{ const payload=migrateBackup(JSON.parse(reader.result)); if(!payload.logs && !payload.customRecipes && !payload.customAddOns && !payload.customShopItems && !payload.generatedShopItems && !payload.pantryItems && !payload.plannedRecipes) throw new Error('No Eat Repeat data found'); if(!confirm('Import backup and replace local logs/recipes/shopping data where included?')) return; if(payload.logs) saveLogs(payload.logs); if(payload.customRecipes) saveCustomRecipes(payload.customRecipes); if(payload.customAddOns) saveCustomAddOns(payload.customAddOns); if(payload.customShopItems) saveCustomShopItems(payload.customShopItems); if(payload.generatedShopItems) saveGeneratedShopItems(payload.generatedShopItems); if(payload.pantryItems) savePantryItems(payload.pantryItems.map(normalizePantryItem).filter(Boolean)); if(payload.shopPrefs) saveShopPrefs(payload.shopPrefs); if(payload.shopState) Object.entries(payload.shopState).forEach(([k,v])=>localStorage.setItem(STORE_PREFIX+k,v)); if(payload.plannedRecipes) savePlannedRecipes(payload.plannedRecipes); if(payload.activeTemplate){ activeTemplate=payload.activeTemplate; localStorage.setItem(STORE_PREFIX+'activeTemplate', activeTemplate); } if(payload.aiRequest){ activeAiRequest=payload.aiRequest; localStorage.setItem(STORE_PREFIX+'aiRequest', activeAiRequest); } if(payload.aiMealPlan) saveAiMealPlan(payload.aiMealPlan); if(payload.aiWeeklyPlan) saveAiWeeklyPlan(payload.aiWeeklyPlan); if(payload.selectedDate) selectedDate=payload.selectedDate; if(payload.historyRange) historyRange=payload.historyRange; toast('Backup imported'); render(); } catch(err){ alert('Import failed: '+err.message); } }; reader.readAsText(file); }
function quickAddForm(){ return `<div class="card flat"><div class="section-title"><div><h2>Quick add</h2><p>Use a preset or enter rough macros.</p></div></div><div class="badges">${allQuickMealPresets().map(p=>`<button class="btn smallbtn" data-quick-preset="${esc(p.id)}">${esc(p.title)}</button>`).join('')}</div><hr><div class="form-grid"><div class="full"><label>Meal name</label><input data-quick-field="title" placeholder="Rough dinner out / sandwich / snack"></div><div><label>Calories</label><input data-quick-field="calories" type="number" value="700"></div><div><label>Protein g</label><input data-quick-field="protein" type="number" value="35"></div><div><label>Carbs g</label><input data-quick-field="carbs" type="number" value="70"></div><div><label>Fat g</label><input data-quick-field="fat" type="number" value="25"></div><div><label>Fibre g</label><input data-quick-field="fibre" type="number" value="5"></div><div class="full"><button class="btn primary" data-action="save-quick-meal">Add to day</button></div></div></div>`; }
document.addEventListener('click', e=>{
  const backdrop=e.target.closest('[data-modal-backdrop]'); if(backdrop && e.target===backdrop){ beerModalOpen=false; return render(); }
  const tab=e.target.closest('[data-tab]'); if(tab) return setTab(tab.dataset.tab);
  const act=e.target.closest('[data-action]')?.dataset.action;
  if(act==='prev-day') return setSelectedDate(addDays(selectedDate,-1));
  if(act==='next-day') return setSelectedDate(addDays(selectedDate,1));
  if(act==='go-settings') return setTab('settings');
  if(act==='go-recipes') return setTab('recipes');
  if(act==='go-shop') return setTab('shop');
  if(act==='save-day') return toast('Saved locally');
  if(act==='open-beer-modal'){ beerModalOpen=true; return render(); }
  if(act==='close-beer-modal'){ beerModalOpen=false; return render(); }
  if(act==='save-beer-modal'){ const value=document.getElementById('beerModalCount')?.value||0; const beers=updateBeerCount(value); beerModalOpen=false; toast(`${beers} beer${beers===1?'':'s'}`); return render(); }
  if(act==='close-copy-fallback'){ copyFallback=null; return render(); }
  if(act==='select-copy-text'){ selectCopyFallbackText(); return toast('Text selected'); }
  if(act==='retry-copy' && copyFallback) return copyText(copyFallback.text, copyFallback.title);
  if(act==='add-beer'){ const log=getLog(); log.beers=beerCountValue(log.beers)+1; setLog(selectedDate,log); toast(`${log.beers} beer${log.beers===1?'':'s'}`); return render(); }
  if(act==='export-ai-handoff') return exportAiRequest();
  if(act==='download-ai-request') return downloadAiRequest();
  if(act==='copy-ai-context') return copyAiContext();
  if(act==='copy-ai-import-format') return copyAiImportFormat();
  if(act==='copy-friend-pack') return copyFriendPack();
  if(act==='import-ai-json') return importAiText();
  if(act==='fill-ai-template'){ const el=document.getElementById('aiImportText'); if(el) el.value=aiImportTemplateV2(); return; }
  if(act==='clear-ai-plan'){ writeJSON('aiMealPlan', null); writeJSON('aiWeeklyPlan', null); toast('AI plan cleared'); return render(); }
  if(act==='tick-planned'){ const log=getLog(); let pantryUsed=0; getPlan(planDayForDate(selectedDate)).forEach(m=>{ const key=mealKey(m); if(!log.meals[key]) pantryUsed+=applyMealPantryUse(m,true); log.meals[key]=true; }); setLog(selectedDate,log); toast(pantryUsed?`Planned meals ticked · pantry updated`:'Planned meals ticked'); return render(); }
  if(act==='show-quick-add'){ const wrap=document.getElementById('quickAdd'); if(wrap){ wrap.innerHTML=quickAddForm(); wrap.classList.remove('hide'); } return; }
  if(act==='save-quick-meal'){ const q={}; document.querySelectorAll('[data-quick-field]').forEach(i=>q[i.dataset.quickField]=i.value); const log=getLog(); log.customMeals.push({id:Date.now()+':quick',title:q.title||'Quick meal',calories:num(q.calories),protein:num(q.protein),carbs:num(q.carbs),fat:num(q.fat),fibre:num(q.fibre)}); setLog(selectedDate,log); toast('Meal added'); return render(); }
  if(act==='toggle-recipe-form'){ editingRecipeId=null; const wrap=document.getElementById('recipeFormWrap'); if(wrap) wrap.classList.toggle('hide'); return; }
  if(act==='cancel-recipe-edit'){ editingRecipeId=null; return render(); }
  if(act==='save-recipe') return saveRecipeFromForm();
  if(act==='copy-recipe-import-format') return copyRecipeImportFormat();
  if(act==='fill-recipe-import-example') return fillRecipeImportExample();
  if(act==='import-recipe-json') return importRecipeJsonText();
  if(act==='clear-prep'){ if(confirm('Clear prep ticks?')){ Object.keys(localStorage).filter(k=>k.startsWith(STORE_PREFIX+'prep:')).forEach(k=>localStorage.removeItem(k)); render(); } return; }
  if(act==='copy-shop'){ const items=shopRangeItems().filter(i=>shopIncluded(i)&&!shopChecked(i)&&pantryNeedRemaining(i)>0); return copyText(shopCopyText(items)); }
  if(act==='copy-shop-all'){ const items=shopItems().filter(shopIncluded); return copyText(shopCopyText(items)); }
  if(act==='clear-shop'){ if(confirm('Clear bought ticks?')){ Object.keys(localStorage).filter(k=>k.startsWith(STORE_PREFIX+'shop2:')&&k.endsWith(':checked')).forEach(k=>localStorage.removeItem(k)); render(); } return; }
  if(act==='reset-shop-view'){ saveShopPrefs({filter:'all',hideChecked:false,onlyNeeded:true}); render(); return; }
  if(act==='generate-meal-shopping') return refreshGeneratedShopping();
  if(act==='shop-range-selected'){ shopRangeStart=selectedDate; localStorage.setItem(STORE_PREFIX+'shopRangeStart', shopRangeStart); return render(); }
  if(act==='save-pantry-item'){ const ingredient=document.getElementById('pantryNewIngredient')?.value.trim(); const qty=document.getElementById('pantryNewQty')?.value||1; if(!ingredient) return toast('Add a pantry item'); if(savePantryItem(ingredient, qty, 'use')) toast('Pantry updated'); else toast('Use a grocery item'); return render(); }
  if(act==='save-shop-item'){ const ingredient=document.getElementById('shopNewIngredient')?.value.trim(); if(!ingredient) return toast('Add an item name'); const item={id:'custom_'+Date.now().toString(36)+'_'+Math.random().toString(36).slice(2,6),ingredient,amount:document.getElementById('shopNewAmount')?.value.trim()||'',category:document.getElementById('shopNewCategory')?.value.trim()||'Extras',used:document.getElementById('shopNewUsed')?.value.trim()||'',notes:document.getElementById('shopNewNotes')?.value.trim()||''}; const items=shopCustomItems(); items.push(item); saveCustomShopItems(items); toast('Shopping item added'); render(); return; }
  if(act==='add-recipe-shopping'){ const sel=document.getElementById('shopRecipeSelect'); return addRecipeIngredientsToShopping(sel?.value||''); }
  if(act==='export-data') return exportData();
  if(act==='clear-logs'){ if(confirm('Clear all daily logs?')){ writeJSON('logs',{}); toast('Logs cleared'); render(); } return; }
  if(act==='clear-recipes'){ if(confirm('Delete all custom recipes?')){ writeJSON('customRecipes',[]); toast('Recipes cleared'); render(); } return; }
  const sf=e.target.closest('[data-shop-filter]'); if(sf){ const p=shopPrefs(); p.filter=sf.dataset.shopFilter; saveShopPrefs(p); return render(); }
  const rangeDays=e.target.closest('[data-shop-range-days]'); if(rangeDays){ shopRangeDays=Number(rangeDays.dataset.shopRangeDays)||4; localStorage.setItem(STORE_PREFIX+'shopRangeDays', shopRangeDays); return render(); }
  const pantryFromShop=e.target.closest('[data-pantry-from-shop]'); if(pantryFromShop){ const item=shopItemById(pantryFromShop.dataset.pantryFromShop); if(item && savePantryItem(item.ingredient, 1, 'use')) toast('Added to pantry'); return render(); }
  const pantryStep=e.target.closest('[data-pantry-step]'); if(pantryStep){ const [id,delta]=pantryStep.dataset.pantryStep.split('|'); adjustPantryItem(id, num(delta)); return render(); }
  const delPantry=e.target.closest('[data-delete-pantry]'); if(delPantry){ deletePantryItem(delPantry.dataset.deletePantry); toast('Pantry item deleted'); return render(); }
  const delShop=e.target.closest('[data-delete-shop-item]'); if(delShop){ if(confirm('Delete this shopping item?')){ saveCustomShopItems(shopCustomItems().filter(x=>x.id!==delShop.dataset.deleteShopItem)); render(); } return; }
  const delAddon=e.target.closest('[data-delete-addon]'); if(delAddon){ if(confirm('Delete this add-on meal?')){ saveCustomAddOns(customAddOns().filter(x=>x.id!==delAddon.dataset.deleteAddon)); render(); } return; }
  const dayBtn=e.target.closest('[data-jump-day]'); if(dayBtn){ const target=dayBtn.dataset.jumpDay; const current=planDayForDate(selectedDate); const diff=(PLAN_TO_JS[target]-PLAN_TO_JS[current]+7)%7; return setSelectedDate(addDays(selectedDate,diff)); }
  const planBtn=e.target.closest('[data-jump-plan-day]'); if(planBtn){ const target=planBtn.dataset.jumpPlanDay; const current=planDayForDate(selectedDate); const diff=(PLAN_TO_JS[target]-PLAN_TO_JS[current]+7)%7; setTab('today'); return setSelectedDate(addDays(selectedDate,diff)); }
  const edit=e.target.closest('[data-edit-date]'); if(edit){ setTab('today'); return setSelectedDate(edit.dataset.editDate); }
  const remove=e.target.closest('[data-remove-custom-meal]'); if(remove){ const log=getLog(); log.customMeals.splice(Number(remove.dataset.removeCustomMeal),1); setLog(selectedDate,log); toast('Removed'); return render(); }
  const preset=e.target.closest('[data-quick-preset]'); if(preset){ const meal=mealFromPreset(preset.dataset.quickPreset); if(meal){ const log=getLog(); log.customMeals.push(meal); setLog(selectedDate,log); toast(`${meal.title} added`); render(); } return; }
  const addRecipe=e.target.closest('[data-add-recipe-to-day]'); if(addRecipe){ const meal=mealFromRecipeId(addRecipe.dataset.addRecipeToDay); if(meal){ const log=getLog(); log.customMeals.push(meal); setLog(selectedDate,log); toast('Added to day'); render(); } return; }
  const planRecipe=e.target.closest('[data-plan-recipe]'); if(planRecipe) return addRecipeToWeek(planRecipe.dataset.planRecipe);
  const remPlan=e.target.closest('[data-remove-planned-recipe]'); if(remPlan){ const [day,id]=remPlan.dataset.removePlannedRecipe.split('|'); return removePlannedRecipe(day,id); }
  const recipeShop=e.target.closest('[data-add-recipe-shopping]'); if(recipeShop) return addRecipeIngredientsToShopping(recipeShop.dataset.addRecipeShopping);
  const editRecipe=e.target.closest('[data-edit-recipe]'); if(editRecipe){ editingRecipeId=editRecipe.dataset.editRecipe; return render(); }
  const del=e.target.closest('[data-delete-recipe]'); if(del){ if(confirm('Delete this custom recipe?')){ saveCustomRecipes(customRecipes().filter(r=>r.id!==del.dataset.deleteRecipe)); render(); } return; }
  const copyRecipe=e.target.closest('[data-copy-recipe-shop]'); if(copyRecipe){ const r=findRecipe(copyRecipe.dataset.copyRecipeShop); if(r) copyText(recipeIngredients(r).join('\n')); return; }
  const dup=e.target.closest('[data-duplicate-recipe]'); if(dup) return duplicateRecipe(dup.dataset.duplicateRecipe);
});
document.addEventListener('change', e=>{
  const meal=e.target.closest('[data-meal-check]'); if(meal){ const log=getLog(); const was=!!log.meals[meal.dataset.mealCheck]; const next=meal.checked; const planned=getPlan(planDayForDate(selectedDate)).find(m=>mealKey(m)===meal.dataset.mealCheck); let pantryUsed=0; if(planned && was!==next) pantryUsed=applyMealPantryUse(planned,next); log.meals[meal.dataset.mealCheck]=next; setLog(selectedDate,log); if(pantryUsed) toast(next?'Pantry reduced':'Pantry restored'); return render(); }
  const templateSelect=e.target.closest('[data-template-select]'); if(templateSelect) return setTemplate(templateSelect.value);
  const shopCheck=e.target.closest('[data-shop-check]'); if(shopCheck){ const item=shopItemById(shopCheck.dataset.shopCheck); if(item) localStorage.setItem(STORE_PREFIX+shopStorageKey(item,'checked'), shopCheck.checked?'1':'0'); return render(); }
  const shopInclude=e.target.closest('[data-shop-include]'); if(shopInclude){ const item=shopItemById(shopInclude.dataset.shopInclude); if(item) localStorage.setItem(STORE_PREFIX+shopStorageKey(item,'include'), shopInclude.checked?'1':'0'); return render(); }
  const shopPref=e.target.closest('[data-shop-pref]'); if(shopPref){ const p=shopPrefs(); p[shopPref.dataset.shopPref]=shopPref.checked; saveShopPrefs(p); return render(); }
  const simple=e.target.closest('[data-simple-check]'); if(simple){ localStorage.setItem(STORE_PREFIX+simple.dataset.simpleCheck, simple.checked?'1':'0'); return; }
  const habit=e.target.closest('[data-habit]'); if(habit){ const log=getLog(); log.habits[habit.dataset.habit]=habit.checked; setLog(selectedDate,log); return render(); }
  const field=e.target.closest('[data-log-field]'); if(field){ const log=getLog(); const k=field.dataset.logField; log[k]=field.value; setLog(selectedDate,log); return render(); }
  const file=e.target.closest('#importFile'); if(file && file.files && file.files[0]) return importData(file.files[0]);
});
document.addEventListener('input', e=>{ const shopAmt=e.target.closest('[data-shop-amount]'); if(shopAmt){ const item=shopItemById(shopAmt.dataset.shopAmount); if(item) localStorage.setItem(STORE_PREFIX+shopStorageKey(item,'amount'), shopAmt.value); return; } const pantryQty=e.target.closest('[data-pantry-qty]'); if(pantryQty){ setPantryItemQty(pantryQty.dataset.pantryQty, pantryQty.value); return; } const field=e.target.closest('[data-log-field]'); if(field && field.tagName==='TEXTAREA'){ const log=getLog(); log[field.dataset.logField]=field.value; setLog(selectedDate,log); } });
render();
if ('serviceWorker' in navigator && ['http:', 'https:'].includes(location.protocol)) {
  window.addEventListener('load', () => {
    navigator.serviceWorker.register('./sw.js').catch(err => console.warn('Service worker registration failed', err));
  });
}
